#!/usr/bin/env -S pnpm exec jiti

import { mkdir, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { currencies, salaryPer, userTypes } from "@guildkit/shared";
import { trimLines } from "@phanect/utils";

const projectRoot = join(import.meta.dirname, "../../..");
const prismaModelDirPath = join(projectRoot, "prisma/models");

const generateEnumSchemas = async () => {
  await mkdir(prismaModelDirPath, { recursive: true });
  await writeFile(
    join(prismaModelDirPath, "enums.prisma"),
    trimLines(`
      // Auto generated by a mise task \`setup:currencies\`. DO NOT EDIT MANUALLY.

      enum Currency {
        ${ currencies.join("\n") }
      }

      enum UserType {
        ${ userTypes.join("\n") }
      }

      enum SalaryPer {
        ${ salaryPer.join("\n") }
      }
    `),
  );
};

await generateEnumSchemas();
